const items = $input.all();
const userId = $('Set: user_id').first().json.user_id;
const first  = items.length > 0 ? items[0].json : null;

// User
const user = first ? {
  id:         first.user_id,
  name:       first.user_name,
  level:      first.user_level,
  avatar_url: first.user_avatar || null
} : { id: userId, name: 'Learner', level: '—', avatar_url: null };

// Stats
const total    = first ? parseInt(first.total_corrections || 0) : 0;
const grammar  = first ? parseInt(first.grammar_count    || 0) : 0;
const vocab    = first ? parseInt(first.vocab_count      || 0) : 0;
const syntax   = first ? parseInt(first.syntax_count     || 0) : 0;

// Determine most improved / needs focus from counts
const cats = [
  { name: 'Grammar',    count: grammar },
  { name: 'Vocabulary', count: vocab   },
  { name: 'Syntax',     count: syntax  }
];
cats.sort(function(a, b) { return b.count - a.count; });

const needsFocus   = cats[0].name;  // most errors = needs focus
const mostImproved = cats[cats.length - 1].name; // least errors = most improved

// Mastery = inverse of error ratio (simple heuristic)
const masteryPct   = total > 0 ? Math.max(0, Math.round(100 - (total / Math.max(total, 50)) * 40)) : 100;
const accuracyPct  = total > 0 ? Math.max(60, Math.round(100 - (total * 0.8)))  : 100;

const stats = {
  total_corrections: total,
  grammar_count:     grammar,
  vocab_count:       vocab,
  syntax_count:      syntax,
  most_improved:     mostImproved,
  needs_focus:       needsFocus,
  mastery_pct:       Math.min(masteryPct, 99),
  accuracy_pct:      Math.min(accuracyPct, 99)
};

// Corrections list
const corrections = items.map(function(item) {
  const r = item.json;
  return {
    id:           r.correction_id,
    wrong_text:   r.wrong_text,
    correct_text: r.correct_text,
    reason:       r.reason       || '',
    topic:        r.topic        || r.session_topic || '',
    vocab_word:   r.vocab_word   || null,
    user_level:   r.user_level   || '',
    created_at:   r.created_at   || null
  };
});

return [{ json: { user, stats, corrections } }];
